package com.example.eventstreamingplatform.service;

import java.time.Instant;
import java.util.UUID;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

import com.example.eventstreamingplatform.model.EventMessage;

@Service
public class EventProducerService {

    private final KafkaTemplate<String, EventMessage> kafkaTemplate;
    private final String topic;

    public EventProducerService(KafkaTemplate<String, EventMessage> kafkaTemplate,
                                @Value("${app.kafka.topic.events}") String topic) {
        this.kafkaTemplate = kafkaTemplate;
        this.topic = topic;
    }

    public void publishEvent(String type, String payload) {
        EventMessage message = new EventMessage(UUID.randomUUID().toString(), type, payload, Instant.now());
        kafkaTemplate.send(topic, message.getId(), message);
    }
}

package com.example.eventstreamingplatform.service;

import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

import com.example.eventstreamingplatform.model.EventMessage;

@Service
public class EventConsumerService {

    @KafkaListener(topics = "${app.kafka.topic.events}", groupId = "event-streaming-platform-group")
    public void consume(EventMessage message) {
        System.out.println("Consumed event: " + message.getId() + " | " + message.getType() + " | " + message.getPayload() + " | " + message.getTimestamp());
    }
}

package com.example.eventstreamingplatform.controller;

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import com.example.eventstreamingplatform.service.EventProducerService;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping
    public ResponseEntity<String> publishEvent(@RequestBody PublishEventRequest request) {
        eventProducerService.publishEvent(request.getType(), request.getPayload());
        return ResponseEntity.accepted().body("Event published");
    }
}

